-- =============================================================================
-- migration-equipment-inventory.sql
-- 25 Apr 2026
--
-- Adds equipment_inventory (master catalog) and extends equipment_requests
-- with inventory_item_id + is_rental + relaxed item_type check.
--
-- Seeded with 264 rows for EHRC: 11 specialty kits (from OT_Grouped_Kits xlsx),
-- 220+ unique instruments (deduped across kits), 13 laparoscopes (from
-- Laparoscopes Tracker xlsx), and the ad-hoc surgical equipment V called out
-- in chat (Stryker Lap Tower, Holmium Laser, Covidien Cautery + Ligasure,
-- Ethicon Focus Harmonic, OT lights/tables/anaesthesia workstation, common
-- consumables).
--
-- Idempotent: CREATE TABLE IF NOT EXISTS, ALTER ADD COLUMN IF NOT EXISTS,
-- INSERTs guarded by NOT EXISTS lookup on (hospital_id, item_label).
-- =============================================================================

-- 1. equipment_inventory ------------------------------------------------------
CREATE TABLE IF NOT EXISTS equipment_inventory (
  id                   UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  hospital_id          UUID NOT NULL REFERENCES hospitals(id),
  category             TEXT NOT NULL CHECK (category IN (
                         'surgical_equipment', 'infrastructure', 'consumable', 'kit'
                       )),
  subcategory          TEXT,
  item_label           TEXT NOT NULL,
  brand                TEXT,
  model                TEXT,
  size_spec            TEXT,
  is_rentable          BOOLEAN NOT NULL DEFAULT TRUE,
  default_vendor_name  TEXT,
  default_vendor_phone TEXT,
  notes                TEXT,
  is_active            BOOLEAN NOT NULL DEFAULT TRUE,
  created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (hospital_id, item_label)
);

CREATE INDEX IF NOT EXISTS idx_ei_hospital_active
  ON equipment_inventory(hospital_id, is_active)
  WHERE is_active = TRUE;
CREATE INDEX IF NOT EXISTS idx_ei_category
  ON equipment_inventory(hospital_id, category, is_active);
CREATE INDEX IF NOT EXISTS idx_ei_label_search
  ON equipment_inventory USING gin (to_tsvector('english', item_label));

-- 2. equipment_requests: extend ----------------------------------------------
ALTER TABLE equipment_requests
  ADD COLUMN IF NOT EXISTS inventory_item_id UUID REFERENCES equipment_inventory(id);

ALTER TABLE equipment_requests
  ADD COLUMN IF NOT EXISTS is_rental BOOLEAN NOT NULL DEFAULT FALSE;

-- Relax item_type CHECK so users can request anything from inventory categories.
-- New constraint covers existing values + the inventory categories.
DO $relax$
BEGIN
  ALTER TABLE equipment_requests DROP CONSTRAINT IF EXISTS equipment_requests_item_type_check;
  ALTER TABLE equipment_requests
    ADD CONSTRAINT equipment_requests_item_type_check
    CHECK (item_type IN (
      'specialty', 'rental', 'implant', 'blood', 'imaging',
      'surgical_equipment', 'infrastructure', 'consumable', 'kit',
      'instrument', 'other'
    ));
EXCEPTION WHEN OTHERS THEN
  -- If constraint name differs, log and continue.
  RAISE NOTICE 'Could not replace item_type constraint cleanly: %', SQLERRM;
END
$relax$;

CREATE INDEX IF NOT EXISTS idx_er_inventory_item
  ON equipment_requests(inventory_item_id) WHERE inventory_item_id IS NOT NULL;

-- 3. Seed: 264 rows for EHRC -------------------------------------------------
-- Resolve EHRC hospital_id once.
DO $seed$
DECLARE
  v_ehrc_id UUID;
BEGIN
  SELECT id INTO v_ehrc_id FROM hospitals WHERE slug = 'ehrc' LIMIT 1;
  IF v_ehrc_id IS NULL THEN
    RAISE EXCEPTION 'EHRC hospital not found (slug=ehrc)';
  END IF;



  RAISE NOTICE 'equipment_inventory seeded for EHRC';
END
$seed$;

-- 4. Marker
VALUES ('25-apr-equipment-inventory', NOW())
ON CONFLICT (name) DO NOTHING;

-- 5. Sanity check
DO $chk$
DECLARE
  v_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_count FROM equipment_inventory
   WHERE hospital_id = (SELECT id FROM hospitals WHERE slug='ehrc');
  RAISE NOTICE 'equipment_inventory has % rows for EHRC', v_count;
END
$chk$;
